import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Check, Zap, Crown, Leaf } from 'lucide-react';
import { getPlans } from '../api/services';

const Plans = () => {
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simulate loading
    const timer = setTimeout(() => {
      setLoading(false);
    }, 500);
    return () => clearTimeout(timer);
  }, []);

  const plansData = [
    {
      id: 1,
      name: 'Weekly Plan',
      price: 29,
      icon: Leaf,
      color: 'from-green-400 to-green-600',
      accentColor: 'bg-green-100',
      textColor: 'text-green-600',
      description: 'Perfect for getting started with healthy eating',
      features: [
        '3 meals per week',
        'Free delivery',
        'Basic meal customization',
        'Mobile app access',
        'Email support',
      ],
      highlighted: false,
    },
    {
      id: 2,
      name: 'Monthly Plan',
      price: 99,
      icon: Zap,
      color: 'from-blue-400 to-blue-600',
      accentColor: 'bg-blue-100',
      textColor: 'text-blue-600',
      description: 'Our most popular choice for consistent nutrition',
      features: [
        '5 meals per week',
        'Free delivery',
        'Full meal customization',
        'Mobile app access',
        'Priority support',
        'Meal tracking dashboard',
        'Weekly nutrition reports',
      ],
      highlighted: true,
    },
    {
      id: 3,
      name: 'Premium Monthly Plan',
      price: 199,
      icon: Crown,
      color: 'from-purple-400 to-purple-600',
      accentColor: 'bg-purple-100',
      textColor: 'text-purple-600',
      description: 'Ultimate plan with personalized nutrition coaching',
      features: [
        'Custom meals per week',
        'Free priority delivery',
        'Full customization',
        'Mobile app access',
        '24/7 priority support',
        'Advanced meal tracking',
        'Recipe videos',
        'Nutritionist consultation',
        'Personalized meal plans',
      ],
      highlighted: false,
    },
  ];

  return (
    <div className="min-h-screen bg-neutral-bg py-12 px-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="text-center mb-16"
        >
          <h1 className="text-5xl font-poppins font-bold text-dark-text mb-4">
            Choose Your Plan
          </h1>
          <p className="text-xl text-gray-600">
            Flexible subscription options tailored to your fitness goals
          </p>
        </motion.div>

        {/* Plans Grid */}
        {loading ? (
          <div className="text-center py-12">
            <p className="text-gray-600">Loading plans...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-20">
            {plansData.map((plan, index) => {
              const IconComponent = plan.icon;
              return (
                <motion.div
                  key={plan.id}
                  initial={{ opacity: 0, y: 20 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.5, delay: index * 0.1 }}
                  whileHover={{ y: -15, transition: { duration: 0.3 } }}
                  className={`relative rounded-3xl overflow-hidden transition-all duration-300 ${
                    plan.highlighted
                      ? 'ring-2 ring-offset-4 ring-blue-400 shadow-2xl'
                      : 'shadow-lg hover:shadow-2xl'
                  }`}
                >
                  {/* Background gradient */}
                  <div
                    className={`absolute inset-0 bg-gradient-to-br ${plan.color} opacity-0 group-hover:opacity-5 transition-opacity duration-300`}
                  />

                  {/* Card content */}
                  <div className={`relative bg-white p-8 ${plan.highlighted ? 'pt-12' : ''}`}>
                    {/* Popular badge */}
                    {plan.highlighted && (
                      <motion.div
                        initial={{ scale: 0 }}
                        whileInView={{ scale: 1 }}
                        className="absolute -top-4 left-1/2 transform -translate-x-1/2"
                      >
                        <div className="bg-gradient-to-r from-blue-400 to-blue-600 text-white px-4 py-1 rounded-full text-sm font-poppins font-bold shadow-lg">
                          MOST POPULAR
                        </div>
                      </motion.div>
                    )}

                    {/* Icon */}
                    <motion.div
                      initial={{ scale: 0, rotate: -20 }}
                      whileInView={{ scale: 1, rotate: 0 }}
                      transition={{ delay: index * 0.1 + 0.2 }}
                      className={`${plan.accentColor} w-16 h-16 rounded-2xl flex items-center justify-center mb-6`}
                    >
                      <IconComponent className={`${plan.textColor}`} size={32} />
                    </motion.div>

                    {/* Plan name */}
                    <h3 className="font-poppins font-bold text-2xl text-dark-text mb-2">
                      {plan.name}
                    </h3>

                    {/* Description */}
                    <p className="text-gray-600 text-sm mb-6 h-10">
                      {plan.description}
                    </p>

                    {/* Price */}
                    <motion.div
                      initial={{ scale: 0.8 }}
                      whileInView={{ scale: 1 }}
                      transition={{ delay: index * 0.1 + 0.1 }}
                      className="mb-8"
                    >
                      <div className="flex items-baseline gap-1">
                        <span className={`text-5xl font-poppins font-bold bg-gradient-to-r ${plan.color} bg-clip-text text-transparent`}>
                          ${plan.price}
                        </span>
                        <span className="text-gray-600 font-inter">/month</span>
                      </div>
                    </motion.div>

                    {/* CTA Button */}
                    <motion.button
                      whileHover={{ scale: 1.05 }}
                      whileTap={{ scale: 0.95 }}
                      className={`w-full py-3 rounded-xl font-poppins font-bold transition-all duration-300 mb-8 ${
                        plan.highlighted
                          ? `bg-gradient-to-r ${plan.color} text-white shadow-lg hover:shadow-xl`
                          : `bg-gray-100 text-dark-text hover:bg-gray-200`
                      }`}
                    >
                      Choose Plan
                    </motion.button>

                    {/* Features list */}
                    <div className="space-y-4">
                      <p className="text-xs font-poppins font-bold text-gray-500 uppercase tracking-wider">
                        What's Included
                      </p>
                      {plan.features.map((feature, featureIndex) => (
                        <motion.div
                          key={featureIndex}
                          initial={{ opacity: 0, x: -10 }}
                          whileInView={{ opacity: 1, x: 0 }}
                          transition={{ delay: index * 0.1 + featureIndex * 0.05 }}
                          className="flex items-start gap-3"
                        >
                          <div className={`${plan.accentColor} rounded-full p-1 mt-1 flex-shrink-0`}>
                            <Check className={`${plan.textColor}`} size={16} />
                          </div>
                          <span className="text-gray-700 text-sm font-inter">
                            {feature}
                          </span>
                        </motion.div>
                      ))}
                    </div>
                  </div>

                  {/* Animated border effect */}
                  <motion.div
                    className={`absolute inset-0 rounded-3xl pointer-events-none ${
                      plan.highlighted
                        ? `bg-gradient-to-r ${plan.color} opacity-0`
                        : 'bg-gradient-to-r from-transparent via-white to-transparent opacity-0'
                    }`}
                    animate={{
                      opacity: plan.highlighted ? [0, 0.1, 0] : [0, 0.05, 0],
                    }}
                    transition={{
                      duration: 3,
                      repeat: Infinity,
                    }}
                  />
                </motion.div>
              );
            })}
          </div>
        )}

        {/* FAQ Section */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          className="mt-20"
        >
          <h2 className="text-3xl font-poppins font-bold text-dark-text mb-8 text-center">
            Frequently Asked Questions
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {[
              {
                q: 'Can I change my plan anytime?',
                a: 'Yes, you can upgrade or downgrade your plan at any time. Changes take effect from the next billing cycle.',
              },
              {
                q: 'Is there a contract?',
                a: 'No contracts required. Cancel anytime with no penalties or hidden fees.',
              },
              {
                q: 'Do you offer refunds?',
                a: 'We offer a 7-day money-back guarantee if you\'re not satisfied with our service.',
              },
              {
                q: 'Can I customize my meals?',
                a: 'Yes, with Standard and Premium plans you can customize your meal preferences.',
              },
            ].map((faq, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className="bg-white rounded-2xl p-6 shadow-premium"
              >
                <h3 className="font-poppins font-bold text-dark-text mb-3">
                  {faq.q}
                </h3>
                <p className="text-gray-600">{faq.a}</p>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>
    </div>
  );
};

export default Plans;
